import { useEffect } from '../lib/teact/teact';
import styles from '../components/ui/Menu.module.scss';

// This effect implements closing menus by clicking outside of them
// without adding extra elements to the DOM
export default function useVirtualBackdrop(isOpen, menuRef, onClose) {
  useEffect(() => {
    const handleEvent = e => {
      const menu = menuRef.current;
      const target = e.target;
      if (!menu || !target) {
        return;
      }
      if (!menu.contains(e.target) || target.classList.contains(styles.backdrop)) {
        e.preventDefault();
        e.stopPropagation();
        if (onClose) {
          onClose();
        }
      }
    };
    if (isOpen && onClose) {
      document.addEventListener('mousedown', handleEvent);
    }
    return () => {
      document.removeEventListener('mousedown', handleEvent);
    };
  }, [isOpen, menuRef, onClose]);
}