export function updateTokenPriceHistory(global, slug, partial) {
  const {
    bySlug
  } = global.tokenPriceHistory;
  return {
    ...global,
    tokenPriceHistory: {
      bySlug: {
        ...bySlug,
        [slug]: {
          ...bySlug[slug],
          ...partial
        }
      }
    }
  };
}
export function updateTokenInfo(global, partial) {
  return {
    ...global,
    tokenInfo: {
      ...global.tokenInfo,
      bySlug: {
        ...global.tokenInfo.bySlug,
        ...partial
      }
    }
  };
}